targets.expr:
histogram_quantile(0.50, sum(rate(erpc_upstream_request_duration_seconds_bucket{
    network=~"${network:regex}",
    vendor=~"${vendor:regex}",
    category=~"${category:regex}",
    project=~"${project:regex}"
}[30s])) by (le, project, vendor, category))

topk(20, avg by (network) (
  erpc_selection_eligible_upstreams{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}"
  }
))

avg by (network, upstream) (
  erpc_selection_score{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}",
      upstream=~"${upstream:regex}"
  }
)

avg by (network, upstream) (
  erpc_selection_position{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}",
      upstream=~"${upstream:regex}"
  }
)

sort_desc(
  max by (network, upstream) (
    erpc_selection_excluded_seconds{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}",
      upstream=~"${upstream:regex}"
    } > 60
  )
)

sum by (reason) (
  rate(erpc_selection_exclusion_total{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}",
      upstream=~"${upstream:regex}"
  }[5m])
)

topk(20,
  sum by (network, upstream, reason) (
    rate(erpc_selection_exclusion_total{
        cluster=~"${cluster:regex}",
        region=~"${region:regex}",
        project=~"${project:regex}",
        network=~"${network:regex}",
        network!~"${ignore_network:regex}",
        upstream=~"${upstream:regex}"
    }[5m])
  )
)

topk(20, sum by (network) (
  rate(erpc_selection_primary_switch_total{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}"
  }[5m])
))

topk(20, sum by (network, upstream) (
  rate(erpc_selection_sticky_hold_total{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}",
      upstream=~"${upstream:regex}"
  }[5m])
))

sum by (le) (
  rate(erpc_selection_readmit_age_seconds_bucket{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}"
  }[$__rate_interval])
)

sum by (reason) (
  rate(erpc_selection_shadow_exclusion_total{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      network!~"${ignore_network:regex}",
      upstream=~"${upstream:regex}"
  }[5m])
)

sum by (action, reason) (
  rate(erpc_upstream_cordon_event_total{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}",
      project=~"${project:regex}",
      network=~"${network:regex}",
      upstream=~"${upstream:regex}"
  }[5m])
)

bottomk(30, 
  sum by (network, category, finality) (
    erpc_consensus_misbehavior_detected_total{
      network=~"${network:regex}",
      project=~"${project:regex}",
      category=~"${category:regex}"
    })
  /
  sum by (network, category, finality) (
    erpc_consensus_total{
      network=~"${network:regex}",
      project=~"${project:regex}",
      category=~"${category:regex}"
    })
)

topk(20, sum by (bucket, network) (
  increase(erpc_network_evm_block_range_requested_total{
    network=~"${network:regex}",network!~"${ignore_network:regex}",category=~"${category:regex}",project=~"${project:regex}",vendor=~"${vendor:regex}",
    category=~"(eth_getBlockByNumber|eth_getBlockByHash|eth_blockNumber|eth_getLogs|eth_getTransactionByHash|eth_getTransactionReceipt|eth_getBlockReceipts)"
  }[$__range])
))

topk(10,
  (
    sum by (network, bucket) (
      increase(erpc_network_evm_block_range_requested_total{
        network=~"${network:regex}",network!~"${ignore_network:regex}",
        category=~"${category:regex}",
        project=~"${project:regex}",
        vendor=~"${vendor:regex}",
        # bucket!~"(TIP|LATEST|FUTURE|FINALIZED)",
        category=~"(eth_getBlockByNumber|eth_getBlockByHash|eth_getLogs|eth_blockNumber|eth_getTransactionByHash|eth_getTransactionReceipt|eth_getBlockReceipts)"
      }[$__range])
    )
  )
)

sum by (category, bucket) (
  increase(erpc_network_evm_block_range_requested_total{
    network=~"${network:regex}",category=~"${category:regex}",project=~"${project:regex}",
    category!~"(eth_getBlockByNumber|eth_getBlockByHash|eth_getLogs|eth_blockNumber|eth_getTransactionByHash|eth_getTransactionReceipt|eth_getBlockReceipts)"
  }[5m])
)

topk(20,
  sum by (network, bucket) (
    increase(erpc_network_evm_block_range_requested_total{
      network=~"${network:regex}",category=~"${category:regex}",project=~"${project:regex}",
      category!~"(eth_getBlockByNumber|eth_getBlockByHash|eth_getLogs|eth_blockNumber|eth_getTransactionByHash|eth_getTransactionReceipt|eth_getBlockReceipts)"
    }[$__range])
  )
)

sum(increase(erpc_auth_failed_total{
      cluster=~"${cluster:regex}",
      region=~"${region:regex}"
}[$__interval])) by (project, region, strategy, reason, agent_name) > 0
